-- Table for querying products by category
CREATE TABLE IF NOT EXISTS ecommerce.products_by_category (
 category TEXT,
 product_id UUID,
 name TEXT,
 price DECIMAL,
 PRIMARY KEY (category, product_id)
) WITH CLUSTERING ORDER BY (product_id DESC);

-- Table with compound partition key
CREATE TABLE IF NOT EXISTS ecommerce.order_items (
