);

import com.datastax.driver.core.*;
import com.datastax.driver.core.querybuilder.QueryBuilder;
import java.util.*;

public class CassandraExample {
 private Cluster cluster;
 private Session session;

 public void connect(String node, int port) {
 cluster = Cluster.builder()
 .addContactPoint(node)
 .withPort(port)
 .build();
 session = cluster.connect("ecommerce");
 }

 public void insertProduct(String name, String category, double price) {
 String cql = "INSERT INTO products (product_id, name, category, price, stock, created_at) " +
 "VALUES (uuid(), '" + name + "', '" + category + "', " + price + ", 100, now())";
 session.execute(cql);
 }

 public List<Row> getProductsByCategory(String category) {
 return session.execute("SELECT * FROM products_by_category WHERE category = '" + category + "'")
 .all();
 }

 public void close() {
 session.close();
 cluster.close();
 }
}
